    fn is_active_list_map_object_bool_field_list_edge(
        &self,
        list: NodeId,
        value: NodeId,
        operator_slot: NodeSlot,
    ) -> bool {
        let Some(list_state) = self.slot_value(list) else {
            return false;
        };
        let Some(value_state) = self.slot_value(value) else {
            return false;
        };
        let IrNodeKind::ListMapObjectBoolField { field, .. } = &self.nodes[operator_slot].kind
        else {
            return false;
        };
        match (&list_state.value, &value_state.value) {
            (KernelValue::List(items), KernelValue::Bool(next_bool)) => {
                let next_bool_value = KernelValue::from(*next_bool);
                let changes_any = items.iter().any(|item| {
                    let KernelValue::Object(fields) = item else {
                        return true;
                    };
                    fields.get(field.as_str()) != Some(&next_bool_value)
                });
                if changes_any {
                    true
                } else {
                    self.is_active_projected_output_edge(
                        operator_slot,
                        &list_state.value,
                        list_state.last_changed.max(value_state.last_changed),
                    )
                }
            }
            (KernelValue::Skip, _) | (_, KernelValue::Skip) => self
                .is_active_projected_output_edge(
                    operator_slot,
                    &KernelValue::Skip,
                    list_state.last_changed.max(value_state.last_changed),
                ),
            _ => true,
        }
    }

    fn is_active_list_retain_object_bool_field_edge(
        &self,
        list: NodeId,
        field: &str,
        keep_if: bool,
        operator_slot: NodeSlot,
    ) -> bool {
        let Some(list_state) = self.slot_value(list) else {
            return false;
        };
        match &list_state.value {
            KernelValue::List(items) => {
                let mut next = Vec::with_capacity(items.len());
                for item in items {
                    let KernelValue::Object(fields) = item else {
                        return true;
                    };
                    let field_value = match fields.get(field) {
                        Some(KernelValue::Bool(value)) => *value,
                        Some(KernelValue::Skip) | None => false,
                        _ => return true,
                    };
                    if field_value == keep_if {
                        next.push(item.clone());
                    }
                }
                self.is_active_projected_output_edge(
                    operator_slot,
                    &KernelValue::List(next),
                    list_state.last_changed,
                )
            }
            KernelValue::Skip => self.is_active_projected_output_edge(
                operator_slot,
                &KernelValue::Skip,
                list_state.last_changed,
            ),
            _ => true,
        }
    }

    fn is_active_list_map_toggle_match_edge(
        &self,
        match_value: NodeId,
        operator_slot: NodeSlot,
    ) -> bool {
        let Some(match_value_state) = self.slot_value(match_value) else {
            return false;
        };
        if self.control_inputs_changed(operator_slot, &match_value_state.value, None) {
            return true;
        }
        if match_value_state.last_changed <= self.values[operator_slot].last_changed {
            return false;
        }
        let IrNodeKind::ListMapToggleObjectBoolFieldByFieldEq {
            list, match_field, ..
        } = &self.nodes[operator_slot].kind
        else {
            return false;
        };
        let Some(list_state) = self.slot_value(*list) else {
            return false;
        };
        match &list_state.value {
            KernelValue::List(items) => {
                let matches_any = items.iter().any(|item| {
                    let KernelValue::Object(fields) = item else {
                        return false;
                    };
                    fields.get(match_field.as_str()) == Some(&match_value_state.value)
                });
                if matches_any {
                    true
                } else {
                    self.is_active_projected_output_edge(
                        operator_slot,
                        &list_state.value,
                        list_state.last_changed.max(match_value_state.last_changed),
                    )
                }
            }
            KernelValue::Skip => self.is_active_projected_output_edge(
                operator_slot,
                &KernelValue::Skip,
                list_state.last_changed.max(match_value_state.last_changed),
            ),
            _ => false,
        }
    }

