    fn function_capture_dependencies(&self, function: FunctionId) -> &[NodeId] {
        self.functions
            .get(function.0 as usize)
            .and_then(|template| template.as_ref())
            .map(|template| template.capture_dependencies.as_slice())
            .unwrap_or(&[])
    }

    fn function_capture_snapshot_with_last_changed(
        &self,
        function: FunctionId,
    ) -> Result<(Option<KernelValue>, Option<CausalSeq>), String> {
        let dependencies = self.function_capture_dependencies(function);
        if dependencies.is_empty() {
            return Ok((None, None));
        }

        let mut values = Vec::with_capacity(dependencies.len());
        let mut last_changed = CausalSeq::new(0, 0);
        for dependency in dependencies {
            let state = self.value(*dependency)?;
            last_changed = last_changed.max(state.last_changed);
            values.push(state.value.clone());
        }
        Ok((Some(KernelValue::List(values)), Some(last_changed)))
    }

    fn function_capture_snapshot(
        &self,
        function: FunctionId,
    ) -> Result<Option<KernelValue>, String> {
        self.function_capture_snapshot_with_last_changed(function)
            .map(|(snapshot, _)| snapshot)
    }

    fn is_active_call_edge(
        &self,
        function: FunctionId,
        args: &[NodeId],
        operator_slot: NodeSlot,
    ) -> bool {
        let mut primary = Vec::with_capacity(args.len());
        let mut primary_last_changed = CausalSeq::new(0, 0);
        for arg in args {
            let Some(state) = self.slot_value(*arg) else {
                return true;
            };
            primary_last_changed = primary_last_changed.max(state.last_changed);
            primary.push(state.value.clone());
        }
        let primary = KernelValue::List(primary);
        let Ok((secondary, secondary_last_changed)) =
            self.function_capture_snapshot_with_last_changed(function)
        else {
            return true;
        };
        self.control_inputs_changed_or_seq_advanced(
            operator_slot,
            &primary,
            primary_last_changed,
            secondary.as_ref(),
            secondary_last_changed,
        )
    }

    fn is_active_list_map_edge(
        &self,
        function: FunctionId,
        list: NodeId,
        operator_slot: NodeSlot,
    ) -> bool {
        let Some(list_state) = self.slot_value(list) else {
            return false;
        };
        let Ok((secondary, secondary_last_changed)) =
            self.function_capture_snapshot_with_last_changed(function)
        else {
            return true;
        };
        self.control_inputs_changed_or_seq_advanced(
            operator_slot,
            &list_state.value,
            list_state.last_changed,
            secondary.as_ref(),
            secondary_last_changed,
        )
    }

