    fn is_active_list_sum_edge(&self, list: NodeId, operator_slot: NodeSlot) -> bool {
        let Some(list_state) = self.slot_value(list) else {
            return false;
        };
        match &list_state.value {
            KernelValue::List(items) => {
                let mut sum = 0.0;
                for item in items {
                    let KernelValue::Number(number) = item else {
                        return true;
                    };
                    sum += number;
                }
                self.is_active_projected_output_edge(
                    operator_slot,
                    &KernelValue::from(sum),
                    list_state.last_changed,
                )
            }
            KernelValue::Skip => self.is_active_projected_output_edge(
                operator_slot,
                &KernelValue::Skip,
                list_state.last_changed,
            ),
            _ => true,
        }
    }

    fn is_active_field_read_edge(
        &self,
        object: NodeId,
        field: &str,
        operator_slot: NodeSlot,
    ) -> bool {
        let Some(object_state) = self.slot_value(object) else {
            return false;
        };
        let current = &self.values[operator_slot];
        match &object_state.value {
            KernelValue::Object(fields) => {
                let projected = fields.get(field).cloned().unwrap_or(KernelValue::Skip);
                current.value != projected || object_state.last_changed > current.last_changed
            }
            KernelValue::Skip => {
                current.value != KernelValue::Skip
                    || object_state.last_changed > current.last_changed
            }
            _ => true,
        }
    }

