    #[test]
    fn non_tail_block_input_update_does_not_revisit_downstream_closure() {
        let nodes = vec![
            IrNode {
                id: NodeId(1),
                source_expr: None,
                kind: IrNodeKind::SourcePort(SourcePortId(30)),
            },
            IrNode {
                id: NodeId(2),
                source_expr: None,
                kind: IrNodeKind::Literal(KernelValue::from("tail")),
            },
            IrNode {
                id: NodeId(3),
                source_expr: None,
                kind: IrNodeKind::Block {
                    inputs: vec![NodeId(1), NodeId(2)],
                },
            },
            IrNode {
                id: NodeId(4),
                source_expr: None,
                kind: IrNodeKind::SinkPort {
                    port: SinkPortId(30),
                    input: NodeId(3),
                },
            },
        ];
        let mut executor = IrExecutor::new(nodes).expect("block ir executes");
        let actor = ActorId {
            index: 0,
            generation: 0,
        };

        assert_eq!(
            executor.sink_value(SinkPortId(30)),
            Some(&KernelValue::from("tail"))
        );
        let before_block = executor.evaluation_count(NodeId(3));
        let before_sink = executor.evaluation_count(NodeId(4));

        executor
            .apply_messages(&[(
                actor,
                Msg::SourcePulse {
                    port: SourcePortId(30),
                    value: KernelValue::from("head"),
                    seq: CausalSeq::new(1, 0),
                },
            )])
            .expect("non-tail block input pulse is accepted");

        assert_eq!(
            executor.sink_value(SinkPortId(30)),
            Some(&KernelValue::from("tail"))
        );
        assert_eq!(executor.evaluation_count(NodeId(3)), before_block);
        assert_eq!(executor.evaluation_count(NodeId(4)), before_sink);
    }

    #[test]
    fn converged_block_tail_dirty_root_does_not_revisit_downstream_closure() {
        let nodes = vec![
            IrNode {
                id: NodeId(1),
                source_expr: None,
                kind: IrNodeKind::Literal(KernelValue::from("head")),
            },
            IrNode {
                id: NodeId(2),
                source_expr: None,
                kind: IrNodeKind::SourcePort(SourcePortId(31)),
            },
            IrNode {
                id: NodeId(3),
                source_expr: None,
                kind: IrNodeKind::Block {
                    inputs: vec![NodeId(1), NodeId(2)],
                },
            },
            IrNode {
                id: NodeId(4),
                source_expr: None,
                kind: IrNodeKind::SinkPort {
                    port: SinkPortId(31),
                    input: NodeId(3),
                },
            },
        ];
        let mut executor = IrExecutor::new(nodes).expect("block ir executes");
        let tail = executor.node_slot(NodeId(2)).expect("tail slot");
        assert!(executor.accept_input_update(
            tail,
            KernelValue::from("tail"),
            CausalSeq::new(1, 0),
        ));
        executor
            .recompute_dirty_slots(&[tail])
            .expect("initial block tail pulse is accepted");

        assert_eq!(
            executor.sink_value(SinkPortId(31)),
            Some(&KernelValue::from("tail"))
        );
        let before_block = executor.evaluation_count(NodeId(3));
        let before_sink = executor.evaluation_count(NodeId(4));

        executor
            .recompute_dirty_slots(&[tail])
            .expect("converged block tail dirty root is accepted");

        assert_eq!(
            executor.sink_value(SinkPortId(31)),
            Some(&KernelValue::from("tail"))
        );
        assert_eq!(executor.evaluation_count(NodeId(3)), before_block);
        assert_eq!(executor.evaluation_count(NodeId(4)), before_sink);
    }

