    #[test]
    fn non_winning_latest_candidate_update_does_not_revisit_downstream_closure() {
        let nodes = vec![
            IrNode {
                id: NodeId(1),
                source_expr: None,
                kind: IrNodeKind::SourcePort(SourcePortId(40)),
            },
            IrNode {
                id: NodeId(2),
                source_expr: None,
                kind: IrNodeKind::Literal(KernelValue::from("seed")),
            },
            IrNode {
                id: NodeId(3),
                source_expr: None,
                kind: IrNodeKind::Hold {
                    seed: NodeId(2),
                    updates: NodeId(1),
                },
            },
            IrNode {
                id: NodeId(4),
                source_expr: None,
                kind: IrNodeKind::SourcePort(SourcePortId(41)),
            },
            IrNode {
                id: NodeId(5),
                source_expr: None,
                kind: IrNodeKind::Latest {
                    inputs: vec![NodeId(3), NodeId(4)],
                },
            },
            IrNode {
                id: NodeId(6),
                source_expr: None,
                kind: IrNodeKind::SinkPort {
                    port: SinkPortId(40),
                    input: NodeId(5),
                },
            },
        ];
        let mut executor = IrExecutor::new(nodes).expect("latest ir executes");
        let actor = ActorId {
            index: 0,
            generation: 0,
        };

        executor
            .apply_messages(&[(
                actor,
                Msg::SourcePulse {
                    port: SourcePortId(40),
                    value: KernelValue::from("winner"),
                    seq: CausalSeq::new(2, 0),
                },
            )])
            .expect("winning latest candidate activates");
        assert_eq!(
            executor.sink_value(SinkPortId(40)),
            Some(&KernelValue::from("winner"))
        );

        executor
            .apply_messages(&[])
            .expect("winning candidate source resets without changing latest output");
        let before_latest = executor.evaluation_count(NodeId(5));
        let before_sink = executor.evaluation_count(NodeId(6));

        executor
            .apply_messages(&[(
                actor,
                Msg::SourcePulse {
                    port: SourcePortId(41),
                    value: KernelValue::from("older"),
                    seq: CausalSeq::new(1, 0),
                },
            )])
            .expect("non-winning latest candidate pulse is accepted");

        assert_eq!(
            executor.sink_value(SinkPortId(40)),
            Some(&KernelValue::from("winner"))
        );
        assert_eq!(executor.evaluation_count(NodeId(5)), before_latest);
        assert_eq!(executor.evaluation_count(NodeId(6)), before_sink);
    }

