    #[test]
    fn winning_latest_candidate_does_not_fallback_to_older_mirror_value_across_hold_state() {
        let nodes = vec![
            IrNode {
                id: NodeId(1),
                source_expr: None,
                kind: IrNodeKind::SourcePort(SourcePortId(169)),
            },
            IrNode {
                id: NodeId(2),
                source_expr: None,
                kind: IrNodeKind::MirrorCell(MirrorCellId(70)),
            },
            IrNode {
                id: NodeId(3),
                source_expr: None,
                kind: IrNodeKind::Latest {
                    inputs: vec![NodeId(1), NodeId(2)],
                },
            },
            IrNode {
                id: NodeId(4),
                source_expr: None,
                kind: IrNodeKind::Hold {
                    seed: NodeId(2),
                    updates: NodeId(3),
                },
            },
            IrNode {
                id: NodeId(5),
                source_expr: None,
                kind: IrNodeKind::SinkPort {
                    port: SinkPortId(169),
                    input: NodeId(4),
                },
            },
        ];
        let mut executor = IrExecutor::new(nodes).expect("latest->hold mirror ir executes");
        let actor = ActorId {
            index: 0,
            generation: 0,
        };

        executor
            .apply_messages(&[(
                actor,
                Msg::MirrorWrite {
                    cell: MirrorCellId(70),
                    value: KernelValue::from("older"),
                    seq: CausalSeq::new(1, 0),
                },
            )])
            .expect("older mirror value is installed");
        assert_eq!(
            executor.sink_value(SinkPortId(169)),
            Some(&KernelValue::from("older"))
        );

        executor
            .apply_messages(&[(
                actor,
                Msg::SourcePulse {
                    port: SourcePortId(169),
                    value: KernelValue::from("winner"),
                    seq: CausalSeq::new(2, 0),
                },
            )])
            .expect("winning latest candidate activates");
        assert_eq!(
            executor.sink_value(SinkPortId(169)),
            Some(&KernelValue::from("winner"))
        );

        let before_latest = executor.evaluation_count(NodeId(3));
        let before_hold = executor.evaluation_count(NodeId(4));
        let before_sink = executor.evaluation_count(NodeId(5));

        executor
            .apply_messages(&[])
            .expect("winning latest candidate reset keeps held state ahead of older mirror");

        assert_eq!(
            executor.sink_value(SinkPortId(169)),
            Some(&KernelValue::from("winner"))
        );
        assert!(executor.evaluation_count(NodeId(3)) > before_latest);
        assert_eq!(executor.evaluation_count(NodeId(4)), before_hold);
        assert_eq!(executor.evaluation_count(NodeId(5)), before_sink);
    }

