    #[test]
    fn hold_update_reset_to_skip_does_not_revisit_downstream_closure_after_initialization() {
        let nodes = vec![
            IrNode {
                id: NodeId(1),
                source_expr: None,
                kind: IrNodeKind::SourcePort(SourcePortId(50)),
            },
            IrNode {
                id: NodeId(2),
                source_expr: None,
                kind: IrNodeKind::SourcePort(SourcePortId(51)),
            },
            IrNode {
                id: NodeId(3),
                source_expr: None,
                kind: IrNodeKind::Hold {
                    seed: NodeId(1),
                    updates: NodeId(2),
                },
            },
            IrNode {
                id: NodeId(4),
                source_expr: None,
                kind: IrNodeKind::SinkPort {
                    port: SinkPortId(50),
                    input: NodeId(3),
                },
            },
        ];
        let mut executor = IrExecutor::new(nodes).expect("hold ir executes");
        let actor = ActorId {
            index: 0,
            generation: 0,
        };

        executor
            .apply_messages(&[(
                actor,
                Msg::SourcePulse {
                    port: SourcePortId(51),
                    value: KernelValue::from("live"),
                    seq: CausalSeq::new(1, 0),
                },
            )])
            .expect("hold initializes from update");
        assert_eq!(
            executor.sink_value(SinkPortId(50)),
            Some(&KernelValue::from("live"))
        );

        let before_hold = executor.evaluation_count(NodeId(3));
        let before_sink = executor.evaluation_count(NodeId(4));

        executor
            .apply_messages(&[])
            .expect("update source resets to skip");

        assert_eq!(
            executor.sink_value(SinkPortId(50)),
            Some(&KernelValue::from("live"))
        );
        assert_eq!(executor.evaluation_count(NodeId(3)), before_hold);
        assert_eq!(executor.evaluation_count(NodeId(4)), before_sink);
    }

