    #[test]
    fn list_map_object_bool_same_value_reapplies_against_updated_hold_list() {
        let nodes = vec![
            IrNode {
                id: NodeId(1),
                source_expr: None,
                kind: IrNodeKind::Literal(KernelValue::Object(std::collections::BTreeMap::from([
                    ("done".to_string(), KernelValue::from(false)),
                ]))),
            },
            IrNode {
                id: NodeId(2),
                source_expr: None,
                kind: IrNodeKind::ListLiteral {
                    items: vec![NodeId(1)],
                },
            },
            IrNode {
                id: NodeId(3),
                source_expr: None,
                kind: IrNodeKind::SourcePort(SourcePortId(102)),
            },
            IrNode {
                id: NodeId(4),
                source_expr: None,
                kind: IrNodeKind::SourcePort(SourcePortId(103)),
            },
            IrNode {
                id: NodeId(5),
                source_expr: None,
                kind: IrNodeKind::Hold {
                    seed: NodeId(2),
                    updates: NodeId(10),
                },
            },
            IrNode {
                id: NodeId(6),
                source_expr: None,
                kind: IrNodeKind::ListMapObjectBoolField {
                    list: NodeId(5),
                    field: "done".to_string(),
                    value: NodeId(3),
                },
            },
            IrNode {
                id: NodeId(7),
                source_expr: None,
                kind: IrNodeKind::Then {
                    source: NodeId(3),
                    body: NodeId(6),
                },
            },
            IrNode {
                id: NodeId(8),
                source_expr: None,
                kind: IrNodeKind::ListAppend {
                    list: NodeId(5),
                    item: NodeId(4),
                },
            },
            IrNode {
                id: NodeId(9),
                source_expr: None,
                kind: IrNodeKind::Then {
                    source: NodeId(4),
                    body: NodeId(8),
                },
            },
            IrNode {
                id: NodeId(10),
                source_expr: None,
                kind: IrNodeKind::Latest {
                    inputs: vec![NodeId(7), NodeId(9)],
                },
            },
            IrNode {
                id: NodeId(11),
                source_expr: None,
                kind: IrNodeKind::SinkPort {
                    port: SinkPortId(102),
                    input: NodeId(5),
                },
            },
        ];
        let mut executor =
            IrExecutor::new(nodes).expect("stateful list map object bool ir executes");
        let actor = ActorId {
            index: 0,
            generation: 0,
        };

        executor
            .apply_messages(&[(
                actor,
                Msg::SourcePulse {
                    port: SourcePortId(102),
                    value: KernelValue::from(true),
                    seq: CausalSeq::new(1, 0),
                },
            )])
            .expect("first bool update pulse is accepted");
        assert_eq!(
            executor.sink_value(SinkPortId(102)),
            Some(&KernelValue::List(vec![KernelValue::Object(
                std::collections::BTreeMap::from([("done".to_string(), KernelValue::from(true))]),
            )]))
        );

        executor
            .apply_messages(&[(
                actor,
                Msg::SourcePulse {
                    port: SourcePortId(103),
                    value: KernelValue::Object(std::collections::BTreeMap::from([(
                        "done".to_string(),
                        KernelValue::from(false),
                    )])),
                    seq: CausalSeq::new(2, 0),
                },
            )])
            .expect("append object pulse is accepted");
        assert_eq!(
            executor.sink_value(SinkPortId(102)),
            Some(&KernelValue::List(vec![
                KernelValue::Object(std::collections::BTreeMap::from([(
                    "done".to_string(),
                    KernelValue::from(true),
                )])),
                KernelValue::Object(std::collections::BTreeMap::from([(
                    "done".to_string(),
                    KernelValue::from(false),
                )])),
            ]))
        );

        executor
            .apply_messages(&[(
                actor,
                Msg::SourcePulse {
                    port: SourcePortId(102),
                    value: KernelValue::from(true),
                    seq: CausalSeq::new(3, 0),
                },
            )])
            .expect("same bool update pulse replays on newer seq");

        assert_eq!(
            executor.sink_value(SinkPortId(102)),
            Some(&KernelValue::List(vec![
                KernelValue::Object(std::collections::BTreeMap::from([(
                    "done".to_string(),
                    KernelValue::from(true),
                )])),
                KernelValue::Object(std::collections::BTreeMap::from([(
                    "done".to_string(),
                    KernelValue::from(true),
                )])),
            ]))
        );
    }

