    fn list_map_toggle_unmatched_value_does_not_revisit_downstream_closure_after_convergence() {
        let nodes = vec![
            IrNode {
                id: NodeId(1),
                source_expr: None,
                kind: IrNodeKind::Literal(KernelValue::Object(std::collections::BTreeMap::from([
                    ("id".to_string(), KernelValue::from(1.0)),
                    ("done".to_string(), KernelValue::from(false)),
                ]))),
            },
            IrNode {
                id: NodeId(2),
                source_expr: None,
                kind: IrNodeKind::ListLiteral {
                    items: vec![NodeId(1)],
                },
            },
            IrNode {
                id: NodeId(3),
                source_expr: None,
                kind: IrNodeKind::SourcePort(SourcePortId(63)),
            },
            IrNode {
                id: NodeId(4),
                source_expr: None,
                kind: IrNodeKind::ListMapToggleObjectBoolFieldByFieldEq {
                    list: NodeId(2),
                    match_field: "id".to_string(),
                    match_value: NodeId(3),
                    bool_field: "done".to_string(),
                },
            },
            IrNode {
                id: NodeId(5),
                source_expr: None,
                kind: IrNodeKind::SinkPort {
                    port: SinkPortId(63),
                    input: NodeId(4),
                },
            },
        ];
        let mut executor = IrExecutor::new(nodes).expect("list toggle ir executes");
        let actor = ActorId {
            index: 0,
            generation: 0,
        };

        executor
            .apply_messages(&[(
                actor,
                Msg::SourcePulse {
                    port: SourcePortId(63),
                    value: KernelValue::from(2.0),
                    seq: CausalSeq::new(1, 0),
                },
            )])
            .expect("unmatched toggle value converges to source list");
        let expected = KernelValue::List(vec![KernelValue::Object(
            std::collections::BTreeMap::from([
                ("id".to_string(), KernelValue::from(1.0)),
                ("done".to_string(), KernelValue::from(false)),
            ]),
        )]);
        assert_eq!(executor.sink_value(SinkPortId(63)), Some(&expected));

        let before_toggle = executor.evaluation_count(NodeId(4));
        let before_sink = executor.evaluation_count(NodeId(5));

        executor
            .apply_messages(&[(
                actor,
                Msg::SourcePulse {
                    port: SourcePortId(63),
                    value: KernelValue::from(2.0),
                    seq: CausalSeq::new(2, 0),
                },
            )])
            .expect("same unmatched toggle value is accepted");

        assert_eq!(executor.sink_value(SinkPortId(63)), Some(&expected));
        assert_eq!(executor.evaluation_count(NodeId(4)), before_toggle);
        assert_eq!(executor.evaluation_count(NodeId(5)), before_sink);
    }

