    #[test]
    fn same_seq_sibling_call_update_revisits_call() {
        let program = IrProgram {
            nodes: vec![
                IrNode {
                    id: NodeId(1),
                    source_expr: None,
                    kind: IrNodeKind::Literal(KernelValue::from("keep-a")),
                },
                IrNode {
                    id: NodeId(2),
                    source_expr: None,
                    kind: IrNodeKind::ListLiteral {
                        items: vec![NodeId(1)],
                    },
                },
                IrNode {
                    id: NodeId(3),
                    source_expr: None,
                    kind: IrNodeKind::SourcePort(SourcePortId(6991)),
                },
                IrNode {
                    id: NodeId(4),
                    source_expr: None,
                    kind: IrNodeKind::SourcePort(SourcePortId(7001)),
                },
                IrNode {
                    id: NodeId(5),
                    source_expr: None,
                    kind: IrNodeKind::Hold {
                        seed: NodeId(2),
                        updates: NodeId(6),
                    },
                },
                IrNode {
                    id: NodeId(6),
                    source_expr: None,
                    kind: IrNodeKind::Then {
                        source: NodeId(4),
                        body: NodeId(7),
                    },
                },
                IrNode {
                    id: NodeId(7),
                    source_expr: None,
                    kind: IrNodeKind::ListAppend {
                        list: NodeId(5),
                        item: NodeId(4),
                    },
                },
                IrNode {
                    id: NodeId(8),
                    source_expr: None,
                    kind: IrNodeKind::Call {
                        function: FunctionId(161),
                        call_site: CallSiteId(6991),
                        args: vec![NodeId(5)],
                    },
                },
                IrNode {
                    id: NodeId(9),
                    source_expr: None,
                    kind: IrNodeKind::Then {
                        source: NodeId(3),
                        body: NodeId(8),
                    },
                },
                IrNode {
                    id: NodeId(10),
                    source_expr: None,
                    kind: IrNodeKind::SinkPort {
                        port: SinkPortId(6991),
                        input: NodeId(9),
                    },
                },
            ],
            functions: vec![IrFunctionTemplate {
                id: FunctionId(161),
                parameter_count: 1,
                output: NodeId(16100),
                nodes: vec![IrNode {
                    id: NodeId(16100),
                    source_expr: None,
                    kind: IrNodeKind::Parameter { index: 0 },
                }],
            }],
            persistence: Vec::new(),
        };
        let mut executor = IrExecutor::new_program(program).expect("same-seq call op ir executes");
        let actor = ActorId {
            index: 0,
            generation: 0,
        };

        let before_call = executor.evaluation_count(NodeId(8));
        let before_sink = executor.evaluation_count(NodeId(10));

        executor
            .apply_messages(&[
                (
                    actor,
                    Msg::SourcePulse {
                        port: SourcePortId(6991),
                        value: KernelValue::from(true),
                        seq: CausalSeq::new(1, 0),
                    },
                ),
                (
                    actor,
                    Msg::SourcePulse {
                        port: SourcePortId(7001),
                        value: KernelValue::from("keep-b"),
                        seq: CausalSeq::new(1, 0),
                    },
                ),
            ])
            .expect("same-seq sibling call update pulse is accepted");

        assert_eq!(
            executor.sink_value(SinkPortId(6991)),
            Some(&KernelValue::List(vec![
                KernelValue::from("keep-a"),
                KernelValue::from("keep-b"),
            ]))
        );
        assert!(executor.evaluation_count(NodeId(8)) > before_call);
        assert!(executor.evaluation_count(NodeId(10)) > before_sink);
    }

