    #[test]
    fn list_count_same_length_update_does_not_revisit_downstream_closure_after_convergence() {
        let nodes = vec![
            IrNode {
                id: NodeId(1),
                source_expr: None,
                kind: IrNodeKind::SourcePort(SourcePortId(66)),
            },
            IrNode {
                id: NodeId(2),
                source_expr: None,
                kind: IrNodeKind::ListCount { list: NodeId(1) },
            },
            IrNode {
                id: NodeId(3),
                source_expr: None,
                kind: IrNodeKind::SinkPort {
                    port: SinkPortId(66),
                    input: NodeId(2),
                },
            },
        ];
        let mut executor = IrExecutor::new(nodes).expect("list count ir executes");
        let actor = ActorId {
            index: 0,
            generation: 0,
        };

        executor
            .apply_messages(&[(
                actor,
                Msg::SourcePulse {
                    port: SourcePortId(66),
                    value: KernelValue::List(vec![KernelValue::from(1.0), KernelValue::from(2.0)]),
                    seq: CausalSeq::new(1, 0),
                },
            )])
            .expect("initial list count pulse is accepted");
        assert_eq!(
            executor.sink_value(SinkPortId(66)),
            Some(&KernelValue::from(2.0))
        );

        let before_count = executor.evaluation_count(NodeId(2));
        let before_sink = executor.evaluation_count(NodeId(3));

        executor
            .apply_messages(&[(
                actor,
                Msg::SourcePulse {
                    port: SourcePortId(66),
                    value: KernelValue::List(vec![KernelValue::from(7.0), KernelValue::from(8.0)]),
                    seq: CausalSeq::new(2, 0),
                },
            )])
            .expect("same-length list count pulse is accepted");

        assert_eq!(
            executor.sink_value(SinkPortId(66)),
            Some(&KernelValue::from(2.0))
        );
        assert_eq!(executor.evaluation_count(NodeId(2)), before_count);
        assert_eq!(executor.evaluation_count(NodeId(3)), before_sink);
    }

    #[test]
    fn list_count_same_length_update_revisits_then_through_eq_control_dependent() {
        let nodes = vec![
            IrNode {
                id: NodeId(1),
                source_expr: None,
                kind: IrNodeKind::SourcePort(SourcePortId(661)),
            },
            IrNode {
                id: NodeId(2),
                source_expr: None,
                kind: IrNodeKind::ListCount { list: NodeId(1) },
            },
            IrNode {
                id: NodeId(3),
                source_expr: None,
                kind: IrNodeKind::Literal(KernelValue::from(2.0)),
            },
            IrNode {
                id: NodeId(4),
                source_expr: None,
                kind: IrNodeKind::Eq {
                    lhs: NodeId(2),
                    rhs: NodeId(3),
                },
            },
            IrNode {
                id: NodeId(5),
                source_expr: None,
                kind: IrNodeKind::Literal(KernelValue::from("selected")),
            },
            IrNode {
                id: NodeId(6),
                source_expr: None,
                kind: IrNodeKind::Then {
                    source: NodeId(4),
                    body: NodeId(5),
                },
            },
            IrNode {
                id: NodeId(7),
                source_expr: None,
                kind: IrNodeKind::SinkPort {
                    port: SinkPortId(661),
                    input: NodeId(6),
                },
            },
        ];
        let mut executor = IrExecutor::new(nodes).expect("list count eq->then ir executes");
        let actor = ActorId {
            index: 0,
            generation: 0,
        };

        executor
            .apply_messages(&[(
                actor,
                Msg::SourcePulse {
                    port: SourcePortId(661),
                    value: KernelValue::List(vec![KernelValue::from(1.0), KernelValue::from(2.0)]),
                    seq: CausalSeq::new(1, 0),
                },
            )])
            .expect("initial list count eq->then pulse is accepted");
        assert_eq!(
            executor.sink_value(SinkPortId(661)),
            Some(&KernelValue::from("selected"))
        );

        let before_count = executor.evaluation_count(NodeId(2));
        let before_eq = executor.evaluation_count(NodeId(4));
        let before_then = executor.evaluation_count(NodeId(6));
        let before_sink = executor.evaluation_count(NodeId(7));

        executor
            .apply_messages(&[(
                actor,
                Msg::SourcePulse {
                    port: SourcePortId(661),
                    value: KernelValue::List(vec![KernelValue::from(7.0), KernelValue::from(8.0)]),
                    seq: CausalSeq::new(2, 0),
                },
            )])
            .expect("same-length list count eq->then pulse is accepted");

        assert_eq!(
            executor.sink_value(SinkPortId(661)),
            Some(&KernelValue::from("selected"))
        );
        assert!(executor.evaluation_count(NodeId(2)) > before_count);
        assert!(executor.evaluation_count(NodeId(4)) > before_eq);
        assert!(executor.evaluation_count(NodeId(6)) > before_then);
        assert!(executor.evaluation_count(NodeId(7)) > before_sink);
    }

