    #[test]
    fn converged_object_dirty_root_does_not_revisit_field_read() {
        let nodes = vec![
            IrNode {
                id: NodeId(1),
                source_expr: None,
                kind: IrNodeKind::SourcePort(SourcePortId(83)),
            },
            IrNode {
                id: NodeId(2),
                source_expr: None,
                kind: IrNodeKind::FieldRead {
                    object: NodeId(1),
                    field: "title".to_string(),
                },
            },
            IrNode {
                id: NodeId(3),
                source_expr: None,
                kind: IrNodeKind::SinkPort {
                    port: SinkPortId(83),
                    input: NodeId(2),
                },
            },
        ];
        let mut executor = IrExecutor::new(nodes).expect("field-read ir executes");
        let source = executor.node_slot(NodeId(1)).expect("source slot");
        assert!(executor.accept_input_update(
            source,
            KernelValue::Object(std::collections::BTreeMap::from([
                ("done".to_string(), KernelValue::from(false)),
                ("title".to_string(), KernelValue::from("todo")),
            ])),
            CausalSeq::new(1, 0),
        ));
        executor
            .recompute_dirty_slots(&[source])
            .expect("initial field-read pulse is accepted");

        assert_eq!(
            executor.sink_value(SinkPortId(83)),
            Some(&KernelValue::from("todo"))
        );
        let before_read = executor.evaluation_count(NodeId(2));
        let before_sink = executor.evaluation_count(NodeId(3));

        executor
            .recompute_dirty_slots(&[source])
            .expect("converged object dirty root is accepted");

        assert_eq!(
            executor.sink_value(SinkPortId(83)),
            Some(&KernelValue::from("todo"))
        );
        assert_eq!(executor.evaluation_count(NodeId(2)), before_read);
        assert_eq!(executor.evaluation_count(NodeId(3)), before_sink);
    }

