    #[test]
    fn ready_frontier_keeps_root_order_independent_quiescent_result() {
        let nodes = vec![
            IrNode {
                id: NodeId(1),
                source_expr: None,
                kind: IrNodeKind::SourcePort(SourcePortId(20)),
            },
            IrNode {
                id: NodeId(2),
                source_expr: None,
                kind: IrNodeKind::SourcePort(SourcePortId(21)),
            },
            IrNode {
                id: NodeId(3),
                source_expr: None,
                kind: IrNodeKind::Add {
                    lhs: NodeId(1),
                    rhs: NodeId(2),
                },
            },
            IrNode {
                id: NodeId(4),
                source_expr: None,
                kind: IrNodeKind::SinkPort {
                    port: SinkPortId(20),
                    input: NodeId(3),
                },
            },
        ];
        let build_executor = || {
            IrExecutor::new_program(IrProgram {
                nodes: nodes.clone(),
                functions: Vec::new(),
                persistence: Vec::new(),
            })
            .expect("executor initializes")
        };

        let mut lhs_then_rhs = build_executor();
        let mut rhs_then_lhs = build_executor();

        for executor in [&mut lhs_then_rhs, &mut rhs_then_lhs] {
            let lhs_slot = executor.node_slot(NodeId(1)).expect("lhs slot");
            let rhs_slot = executor.node_slot(NodeId(2)).expect("rhs slot");
            executor.values[lhs_slot] = ValueState {
                value: KernelValue::from(2.0),
                last_changed: CausalSeq::new(1, 0),
            };
            executor.values[rhs_slot] = ValueState {
                value: KernelValue::from(3.0),
                last_changed: CausalSeq::new(1, 1),
            };
        }

        lhs_then_rhs
            .recompute_dirty_slots(&[
                lhs_then_rhs.node_slot(NodeId(1)).expect("lhs slot"),
                lhs_then_rhs.node_slot(NodeId(2)).expect("rhs slot"),
            ])
            .expect("lhs/rhs frontier drains");
        rhs_then_lhs
            .recompute_dirty_slots(&[
                rhs_then_lhs.node_slot(NodeId(2)).expect("rhs slot"),
                rhs_then_lhs.node_slot(NodeId(1)).expect("lhs slot"),
            ])
            .expect("rhs/lhs frontier drains");

        assert_eq!(
            lhs_then_rhs.sink_value(SinkPortId(20)),
            Some(&KernelValue::from(5.0))
        );
        assert_eq!(lhs_then_rhs.sink_values(), rhs_then_lhs.sink_values());
        assert_eq!(
            lhs_then_rhs.evaluation_count(NodeId(3)),
            rhs_then_lhs.evaluation_count(NodeId(3))
        );
        assert_eq!(
            lhs_then_rhs.evaluation_count(NodeId(4)),
            rhs_then_lhs.evaluation_count(NodeId(4))
        );
    }

    #[test]
    fn stale_source_pulse_is_rejected_by_slot_cutoff() {
        let nodes = vec![
            IrNode {
                id: NodeId(1),
                source_expr: None,
                kind: IrNodeKind::SourcePort(SourcePortId(30)),
            },
            IrNode {
                id: NodeId(2),
                source_expr: None,
                kind: IrNodeKind::Literal(KernelValue::from(1.0)),
            },
            IrNode {
                id: NodeId(3),
                source_expr: None,
                kind: IrNodeKind::Then {
                    source: NodeId(1),
                    body: NodeId(2),
                },
            },
            IrNode {
                id: NodeId(4),
                source_expr: None,
                kind: IrNodeKind::MathSum { input: NodeId(3) },
            },
            IrNode {
                id: NodeId(5),
                source_expr: None,
                kind: IrNodeKind::SinkPort {
                    port: SinkPortId(30),
                    input: NodeId(4),
                },
            },
        ];
        let mut executor = IrExecutor::new_program(IrProgram {
            nodes,
            functions: Vec::new(),
            persistence: Vec::new(),
        })
        .expect("executor initializes");
        let actor = ActorId {
            index: 0,
            generation: 0,
        };

        executor
            .apply_messages(&[(
                actor,
                Msg::SourcePulse {
                    port: SourcePortId(30),
                    value: KernelValue::from("pulse"),
                    seq: CausalSeq::new(2, 0),
                },
            )])
            .expect("fresh pulse executes");
        assert_eq!(
            executor.sink_value(SinkPortId(30)),
            Some(&KernelValue::from(1.0))
        );

        executor
            .apply_messages(&[(
                actor,
                Msg::SourcePulse {
                    port: SourcePortId(30),
                    value: KernelValue::from("stale"),
                    seq: CausalSeq::new(1, 9),
                },
            )])
            .expect("stale pulse is ignored");
        assert_eq!(
            executor.sink_value(SinkPortId(30)),
            Some(&KernelValue::from(1.0))
        );

        executor
            .apply_messages(&[(
                actor,
                Msg::SourcePulse {
                    port: SourcePortId(30),
                    value: KernelValue::from("fresh-again"),
                    seq: CausalSeq::new(2, 1),
                },
            )])
            .expect("newer pulse executes");
        assert_eq!(
            executor.sink_value(SinkPortId(30)),
            Some(&KernelValue::from(2.0))
        );
    }

