    #[test]
    fn fresh_mirror_snapshot_only_resets_targeted_mirror_cutoffs() {
        let mut executor = IrExecutor::new(vec![
            IrNode {
                id: NodeId(1),
                source_expr: None,
                kind: IrNodeKind::MirrorCell(MirrorCellId(60)),
            },
            IrNode {
                id: NodeId(2),
                source_expr: None,
                kind: IrNodeKind::MirrorCell(MirrorCellId(61)),
            },
            IrNode {
                id: NodeId(3),
                source_expr: None,
                kind: IrNodeKind::SinkPort {
                    port: SinkPortId(60),
                    input: NodeId(1),
                },
            },
            IrNode {
                id: NodeId(4),
                source_expr: None,
                kind: IrNodeKind::SinkPort {
                    port: SinkPortId(61),
                    input: NodeId(2),
                },
            },
        ])
        .expect("mirror ir executes");
        executor
            .apply_mirror_write(
                MirrorCellId(60),
                KernelValue::from("fresh-a"),
                CausalSeq::new(5, 0),
            )
            .expect("initial first mirror write applies");
        executor
            .apply_mirror_write(
                MirrorCellId(61),
                KernelValue::from("fresh-b"),
                CausalSeq::new(6, 0),
            )
            .expect("initial mirror writes apply");

        executor
            .apply_mirror_writes_with_fresh_cells(
                [
                    (
                        MirrorCellId(60),
                        KernelValue::from("replayed-a"),
                        CausalSeq::new(3, 0),
                    ),
                    (
                        MirrorCellId(61),
                        KernelValue::from("stale-b"),
                        CausalSeq::new(4, 0),
                    ),
                ],
                &[MirrorCellId(60)],
            )
            .expect("targeted fresh snapshot applies only for requested mirror");

        assert_eq!(
            executor.sink_value(SinkPortId(60)),
            Some(&KernelValue::from("replayed-a"))
        );
        assert_eq!(
            executor.sink_value(SinkPortId(61)),
            Some(&KernelValue::from("fresh-b"))
        );
    }

