    #[test]
    fn link_bind_rebinds_link_read_to_latest_target() {
        let nodes = vec![
            IrNode {
                id: NodeId(1),
                source_expr: None,
                kind: IrNodeKind::SourcePort(SourcePortId(10)),
            },
            IrNode {
                id: NodeId(2),
                source_expr: None,
                kind: IrNodeKind::Literal(KernelValue::from("left")),
            },
            IrNode {
                id: NodeId(3),
                source_expr: None,
                kind: IrNodeKind::Then {
                    source: NodeId(1),
                    body: NodeId(2),
                },
            },
            IrNode {
                id: NodeId(4),
                source_expr: None,
                kind: IrNodeKind::SourcePort(SourcePortId(11)),
            },
            IrNode {
                id: NodeId(5),
                source_expr: None,
                kind: IrNodeKind::Literal(KernelValue::from("right")),
            },
            IrNode {
                id: NodeId(6),
                source_expr: None,
                kind: IrNodeKind::Then {
                    source: NodeId(4),
                    body: NodeId(5),
                },
            },
            IrNode {
                id: NodeId(7),
                source_expr: None,
                kind: IrNodeKind::LinkCell,
            },
            IrNode {
                id: NodeId(8),
                source_expr: None,
                kind: IrNodeKind::LinkBind {
                    value: NodeId(3),
                    target: NodeId(7),
                },
            },
            IrNode {
                id: NodeId(9),
                source_expr: None,
                kind: IrNodeKind::LinkBind {
                    value: NodeId(6),
                    target: NodeId(7),
                },
            },
            IrNode {
                id: NodeId(10),
                source_expr: None,
                kind: IrNodeKind::LinkRead { cell: NodeId(7) },
            },
            IrNode {
                id: NodeId(11),
                source_expr: None,
                kind: IrNodeKind::SinkPort {
                    port: SinkPortId(1),
                    input: NodeId(10),
                },
            },
        ];
        let mut executor = IrExecutor::new(nodes).expect("link ir executes");
        let actor = ActorId {
            index: 0,
            generation: 0,
        };

        executor
            .apply_messages(&[(
                actor,
                Msg::SourcePulse {
                    port: SourcePortId(10),
                    value: KernelValue::from("click"),
                    seq: CausalSeq::new(1, 0),
                },
            )])
            .expect("left bind executes");
        assert_eq!(
            executor.sink_value(SinkPortId(1)),
            Some(&KernelValue::from("left"))
        );
        let first_epoch = executor
            .link_state(NodeId(7))
            .expect("link state")
            .edge_epoch;

        executor
            .apply_messages(&[(
                actor,
                Msg::SourcePulse {
                    port: SourcePortId(11),
                    value: KernelValue::from("click"),
                    seq: CausalSeq::new(2, 0),
                },
            )])
            .expect("right bind executes");
        assert_eq!(
            executor.sink_value(SinkPortId(1)),
            Some(&KernelValue::from("right"))
        );
        assert!(
            executor
                .link_state(NodeId(7))
                .expect("link state")
                .edge_epoch
                > first_epoch
        );
    }

