    #[test]
    fn stale_link_bind_does_not_revisit_hold_update_through_object_literal() {
        let nodes = vec![
            IrNode {
                id: NodeId(1),
                source_expr: None,
                kind: IrNodeKind::SourcePort(SourcePortId(942)),
            },
            IrNode {
                id: NodeId(2),
                source_expr: None,
                kind: IrNodeKind::Literal(KernelValue::from("left")),
            },
            IrNode {
                id: NodeId(3),
                source_expr: None,
                kind: IrNodeKind::Then {
                    source: NodeId(1),
                    body: NodeId(2),
                },
            },
            IrNode {
                id: NodeId(4),
                source_expr: None,
                kind: IrNodeKind::SourcePort(SourcePortId(943)),
            },
            IrNode {
                id: NodeId(5),
                source_expr: None,
                kind: IrNodeKind::Literal(KernelValue::from("right")),
            },
            IrNode {
                id: NodeId(6),
                source_expr: None,
                kind: IrNodeKind::Then {
                    source: NodeId(4),
                    body: NodeId(5),
                },
            },
            IrNode {
                id: NodeId(7),
                source_expr: None,
                kind: IrNodeKind::LinkCell,
            },
            IrNode {
                id: NodeId(8),
                source_expr: None,
                kind: IrNodeKind::LinkBind {
                    value: NodeId(6),
                    target: NodeId(7),
                },
            },
            IrNode {
                id: NodeId(9),
                source_expr: None,
                kind: IrNodeKind::LinkBind {
                    value: NodeId(3),
                    target: NodeId(7),
                },
            },
            IrNode {
                id: NodeId(10),
                source_expr: None,
                kind: IrNodeKind::LinkRead { cell: NodeId(7) },
            },
            IrNode {
                id: NodeId(11),
                source_expr: None,
                kind: IrNodeKind::Literal(KernelValue::from("user")),
            },
            IrNode {
                id: NodeId(12),
                source_expr: None,
                kind: IrNodeKind::ObjectLiteral {
                    fields: vec![
                        ("name".to_string(), NodeId(10)),
                        ("kind".to_string(), NodeId(11)),
                    ],
                },
            },
            IrNode {
                id: NodeId(13),
                source_expr: None,
                kind: IrNodeKind::Then {
                    source: NodeId(4),
                    body: NodeId(12),
                },
            },
            IrNode {
                id: NodeId(14),
                source_expr: None,
                kind: IrNodeKind::Literal(KernelValue::Object(std::collections::BTreeMap::from([
                    ("kind".to_string(), KernelValue::from("user")),
                    ("name".to_string(), KernelValue::from("seed")),
                ]))),
            },
            IrNode {
                id: NodeId(15),
                source_expr: None,
                kind: IrNodeKind::Hold {
                    seed: NodeId(14),
                    updates: NodeId(13),
                },
            },
            IrNode {
                id: NodeId(16),
                source_expr: None,
                kind: IrNodeKind::SinkPort {
                    port: SinkPortId(942),
                    input: NodeId(15),
                },
            },
        ];
        let mut executor =
            IrExecutor::new(nodes).expect("stale link->object_literal->hold ir executes");
        let right_source = executor.node_slot(NodeId(4)).expect("right source slot");
        assert!(executor.accept_input_update(
            right_source,
            KernelValue::from("click"),
            CausalSeq::new(2, 0),
        ));
        executor
            .recompute_dirty_slots(&[right_source])
            .expect("newer right bind through object_literal executes");

        assert_eq!(
            executor.sink_value(SinkPortId(942)),
            Some(&KernelValue::Object(std::collections::BTreeMap::from([
                ("kind".to_string(), KernelValue::from("user")),
                ("name".to_string(), KernelValue::from("right")),
            ])))
        );
        let before_read = executor.evaluation_count(NodeId(10));
        let before_object = executor.evaluation_count(NodeId(12));
        let before_hold = executor.evaluation_count(NodeId(15));
        let before_sink = executor.evaluation_count(NodeId(16));
        assert_eq!(
            executor
                .slot_value(NodeId(12))
                .map(|state| state.last_changed),
            Some(CausalSeq::new(2, 0))
        );
        assert_eq!(
            executor
                .slot_value(NodeId(15))
                .map(|state| state.last_changed),
            Some(CausalSeq::new(2, 0))
        );

        let left_source = executor.node_slot(NodeId(1)).expect("left source slot");
        assert!(executor.accept_input_update(
            left_source,
            KernelValue::from("click"),
            CausalSeq::new(1, 0),
        ));
        executor
            .recompute_dirty_slots(&[left_source])
            .expect("stale left bind through object_literal is accepted");

        assert_eq!(
            executor.sink_value(SinkPortId(942)),
            Some(&KernelValue::Object(std::collections::BTreeMap::from([
                ("kind".to_string(), KernelValue::from("user")),
                ("name".to_string(), KernelValue::from("right")),
            ])))
        );
        assert_eq!(executor.evaluation_count(NodeId(10)), before_read);
        assert_eq!(executor.evaluation_count(NodeId(12)), before_object);
        assert_eq!(executor.evaluation_count(NodeId(15)), before_hold);
        assert_eq!(executor.evaluation_count(NodeId(16)), before_sink);
        assert_eq!(
            executor
                .slot_value(NodeId(12))
                .map(|state| state.last_changed),
            Some(CausalSeq::new(2, 0))
        );
        assert_eq!(
            executor
                .slot_value(NodeId(15))
                .map(|state| state.last_changed),
            Some(CausalSeq::new(2, 0))
        );
    }

