    #[test]
    fn converged_input_dirty_root_does_not_revisit_sink() {
        let nodes = vec![
            IrNode {
                id: NodeId(1),
                source_expr: None,
                kind: IrNodeKind::SourcePort(SourcePortId(10)),
            },
            IrNode {
                id: NodeId(2),
                source_expr: None,
                kind: IrNodeKind::SinkPort {
                    port: SinkPortId(1),
                    input: NodeId(1),
                },
            },
        ];
        let mut executor = IrExecutor::new(nodes).expect("source sink ir executes");
        let source = executor.node_slot(NodeId(1)).expect("source slot");
        assert!(executor.accept_input_update(
            source,
            KernelValue::from("value"),
            CausalSeq::new(1, 0),
        ));
        executor
            .recompute_dirty_slots(&[source])
            .expect("initial sink recompute executes");

        assert_eq!(
            executor.sink_value(SinkPortId(1)),
            Some(&KernelValue::from("value"))
        );
        let before_sink = executor.evaluation_count(NodeId(2));

        executor
            .recompute_dirty_slots(&[source])
            .expect("converged dirty root is accepted");

        assert_eq!(
            executor.sink_value(SinkPortId(1)),
            Some(&KernelValue::from("value"))
        );
        assert_eq!(executor.evaluation_count(NodeId(2)), before_sink);
    }

