    #[test]
    fn executes_function_template_calls_with_parameters_and_captures() {
        let program = IrProgram {
            nodes: vec![
                IrNode {
                    id: NodeId(1),
                    source_expr: None,
                    kind: IrNodeKind::MirrorCell(MirrorCellId(1)),
                },
                IrNode {
                    id: NodeId(2),
                    source_expr: None,
                    kind: IrNodeKind::MirrorCell(MirrorCellId(2)),
                },
                IrNode {
                    id: NodeId(3),
                    source_expr: None,
                    kind: IrNodeKind::Call {
                        function: FunctionId(1),
                        call_site: CallSiteId(1),
                        args: vec![NodeId(1)],
                    },
                },
                IrNode {
                    id: NodeId(4),
                    source_expr: None,
                    kind: IrNodeKind::SinkPort {
                        port: SinkPortId(300),
                        input: NodeId(3),
                    },
                },
            ],
            functions: vec![IrFunctionTemplate {
                id: FunctionId(1),
                parameter_count: 1,
                output: NodeId(102),
                nodes: vec![
                    IrNode {
                        id: NodeId(100),
                        source_expr: None,
                        kind: IrNodeKind::Parameter { index: 0 },
                    },
                    IrNode {
                        id: NodeId(101),
                        source_expr: None,
                        kind: IrNodeKind::Add {
                            lhs: NodeId(100),
                            rhs: NodeId(2),
                        },
                    },
                    IrNode {
                        id: NodeId(102),
                        source_expr: None,
                        kind: IrNodeKind::Add {
                            lhs: NodeId(101),
                            rhs: NodeId(100),
                        },
                    },
                ],
            }],
            persistence: Vec::new(),
        };
        let mut executor = IrExecutor::new_program(program).expect("function program executes");
        let actor = ActorId {
            index: 0,
            generation: 0,
        };

        executor
            .apply_messages(&[
                (
                    actor,
                    Msg::MirrorWrite {
                        cell: MirrorCellId(1),
                        value: KernelValue::from(7.0),
                        seq: CausalSeq::new(1, 0),
                    },
                ),
                (
                    actor,
                    Msg::MirrorWrite {
                        cell: MirrorCellId(2),
                        value: KernelValue::from(10.0),
                        seq: CausalSeq::new(1, 1),
                    },
                ),
            ])
            .expect("first function batch executes");

        assert_eq!(
            executor.sink_value(SinkPortId(300)),
            Some(&KernelValue::from(24.0))
        );
        assert_eq!(executor.function_instance_count(), 1);

        executor
            .apply_messages(&[(
                actor,
                Msg::MirrorWrite {
                    cell: MirrorCellId(1),
                    value: KernelValue::from(8.0),
                    seq: CausalSeq::new(2, 0),
                },
            )])
            .expect("second function batch executes");

        assert_eq!(
            executor.sink_value(SinkPortId(300)),
            Some(&KernelValue::from(26.0))
        );
        assert_eq!(executor.function_instance_count(), 1);
    }

    #[test]
    fn list_map_reuses_stable_function_instances_for_range_items() {
        let program = IrProgram {
            nodes: vec![
                IrNode {
                    id: NodeId(1),
                    source_expr: None,
                    kind: IrNodeKind::Literal(KernelValue::from(1.0)),
                },
                IrNode {
                    id: NodeId(2),
                    source_expr: None,
                    kind: IrNodeKind::Literal(KernelValue::from(3.0)),
                },
                IrNode {
                    id: NodeId(3),
                    source_expr: None,
                    kind: IrNodeKind::MirrorCell(MirrorCellId(10)),
                },
                IrNode {
                    id: NodeId(4),
                    source_expr: None,
                    kind: IrNodeKind::ListRange {
                        from: NodeId(1),
                        to: NodeId(2),
                    },
                },
                IrNode {
                    id: NodeId(5),
                    source_expr: None,
                    kind: IrNodeKind::ListMap {
                        list: NodeId(4),
                        function: FunctionId(2),
                        call_site: CallSiteId(20),
                    },
                },
                IrNode {
                    id: NodeId(6),
                    source_expr: None,
                    kind: IrNodeKind::SinkPort {
                        port: SinkPortId(301),
                        input: NodeId(5),
                    },
                },
            ],
            functions: vec![IrFunctionTemplate {
                id: FunctionId(2),
                parameter_count: 1,
                output: NodeId(202),
                nodes: vec![
                    IrNode {
                        id: NodeId(200),
                        source_expr: None,
                        kind: IrNodeKind::Parameter { index: 0 },
                    },
                    IrNode {
                        id: NodeId(201),
                        source_expr: None,
                        kind: IrNodeKind::Add {
                            lhs: NodeId(200),
                            rhs: NodeId(3),
                        },
                    },
                    IrNode {
                        id: NodeId(202),
                        source_expr: None,
                        kind: IrNodeKind::Add {
                            lhs: NodeId(201),
                            rhs: NodeId(200),
                        },
                    },
                ],
            }],
            persistence: Vec::new(),
        };
        let mut executor = IrExecutor::new_program(program).expect("list map program executes");
        let actor = ActorId {
            index: 0,
            generation: 0,
        };

        executor
            .apply_messages(&[(
                actor,
                Msg::MirrorWrite {
                    cell: MirrorCellId(10),
                    value: KernelValue::from(10.0),
                    seq: CausalSeq::new(1, 0),
                },
            )])
            .expect("first list map batch executes");

        assert_eq!(
            executor.sink_value(SinkPortId(301)),
            Some(&KernelValue::List(vec![
                KernelValue::from(12.0),
                KernelValue::from(14.0),
                KernelValue::from(16.0),
            ]))
        );
        assert_eq!(executor.function_instance_count(), 3);

        executor
            .apply_messages(&[(
                actor,
                Msg::MirrorWrite {
                    cell: MirrorCellId(10),
                    value: KernelValue::from(20.0),
                    seq: CausalSeq::new(2, 0),
                },
            )])
            .expect("second list map batch executes");

        assert_eq!(
            executor.sink_value(SinkPortId(301)),
            Some(&KernelValue::List(vec![
                KernelValue::from(22.0),
                KernelValue::from(24.0),
                KernelValue::from(26.0),
            ]))
        );
        assert_eq!(executor.function_instance_count(), 3);
    }

