    #[test]
    fn executes_lowered_then_ir_keeps_sum_stable_until_next_press() {
        let source = include_str!("../../../playground/frontend/src/examples/then/then.bn");
        let program = try_lower_then(source).expect("then lowers");
        let mut executor = IrExecutor::new(program.ir).expect("then ir executes");
        let actor = ActorId {
            index: 0,
            generation: 0,
        };

        executor
            .apply_messages(&[
                (
                    actor,
                    Msg::SourcePulse {
                        port: program.input_a_tick_port,
                        value: KernelValue::from("tick"),
                        seq: CausalSeq::new(1, 0),
                    },
                ),
                (
                    actor,
                    Msg::SourcePulse {
                        port: program.input_a_tick_port,
                        value: KernelValue::from("tick"),
                        seq: CausalSeq::new(1, 1),
                    },
                ),
                (
                    actor,
                    Msg::SourcePulse {
                        port: program.input_b_tick_port,
                        value: KernelValue::from("tick"),
                        seq: CausalSeq::new(1, 2),
                    },
                ),
            ])
            .expect("timer ticks execute");

        assert_eq!(
            executor.sink_value(program.input_a_sink),
            Some(&KernelValue::from(2.0))
        );
        assert_eq!(
            executor.sink_value(program.input_b_sink),
            Some(&KernelValue::from(10.0))
        );
        assert_eq!(
            executor.sink_value(program.result_sink),
            Some(&KernelValue::Skip)
        );

        executor
            .apply_messages(&[(
                actor,
                Msg::SourcePulse {
                    port: program.addition_press_port,
                    value: KernelValue::from("press"),
                    seq: CausalSeq::new(2, 0),
                },
            )])
            .expect("addition press executes");

        assert_eq!(
            executor.sink_value(program.result_sink),
            Some(&KernelValue::from(12.0))
        );
        dbg!(
            executor.slot_value(NodeId(2216)),
            executor.slot_value(NodeId(2219)),
            executor.slot_value(NodeId(2220)),
            executor.slot_value(NodeId(2224)),
            executor.slot_value(NodeId(2226))
        );

        executor
            .apply_messages(&[
                (
                    actor,
                    Msg::SourcePulse {
                        port: program.input_a_tick_port,
                        value: KernelValue::from("tick"),
                        seq: CausalSeq::new(3, 0),
                    },
                ),
                (
                    actor,
                    Msg::SourcePulse {
                        port: program.input_a_tick_port,
                        value: KernelValue::from("tick"),
                        seq: CausalSeq::new(3, 1),
                    },
                ),
                (
                    actor,
                    Msg::SourcePulse {
                        port: program.input_b_tick_port,
                        value: KernelValue::from("tick"),
                        seq: CausalSeq::new(3, 2),
                    },
                ),
            ])
            .expect("later timer ticks execute");

        assert_eq!(
            executor.sink_value(program.input_a_sink),
            Some(&KernelValue::from(4.0))
        );
        assert_eq!(
            executor.sink_value(program.input_b_sink),
            Some(&KernelValue::from(20.0))
        );
        assert_eq!(
            executor.sink_value(program.result_sink),
            Some(&KernelValue::from(12.0))
        );
        dbg!(
            executor.slot_value(NodeId(2216)),
            executor.slot_value(NodeId(2219)),
            executor.slot_value(NodeId(2220)),
            executor.slot_value(NodeId(2222)),
            executor.slot_value(NodeId(2224)),
            executor.slot_value(NodeId(2226))
        );
    }

    #[test]
    fn executes_lowered_when_ir_keeps_result_stable_until_operation_changes() {
        let source = include_str!("../../../playground/frontend/src/examples/when/when.bn");
        let program = try_lower_when(source).expect("when lowers");
        let mut executor = IrExecutor::new(program.ir).expect("when ir executes");
        let actor = ActorId {
            index: 0,
            generation: 0,
        };

        executor
            .apply_messages(&[
                (
                    actor,
                    Msg::SourcePulse {
                        port: program.input_a_tick_port,
                        value: KernelValue::from("tick"),
                        seq: CausalSeq::new(1, 0),
                    },
                ),
                (
                    actor,
                    Msg::SourcePulse {
                        port: program.input_a_tick_port,
                        value: KernelValue::from("tick"),
                        seq: CausalSeq::new(1, 1),
                    },
                ),
                (
                    actor,
                    Msg::SourcePulse {
                        port: program.input_b_tick_port,
                        value: KernelValue::from("tick"),
                        seq: CausalSeq::new(1, 2),
                    },
                ),
                (
                    actor,
                    Msg::SourcePulse {
                        port: program.addition_press_port,
                        value: KernelValue::from("press"),
                        seq: CausalSeq::new(1, 3),
                    },
                ),
            ])
            .expect("ticks and addition execute");

        assert_eq!(
            executor.sink_value(program.result_sink),
            Some(&KernelValue::from(12.0))
        );

        executor
            .apply_messages(&[
                (
                    actor,
                    Msg::SourcePulse {
                        port: program.input_a_tick_port,
                        value: KernelValue::from("tick"),
                        seq: CausalSeq::new(2, 0),
                    },
                ),
                (
                    actor,
                    Msg::SourcePulse {
                        port: program.input_a_tick_port,
                        value: KernelValue::from("tick"),
                        seq: CausalSeq::new(2, 1),
                    },
                ),
                (
                    actor,
                    Msg::SourcePulse {
                        port: program.input_b_tick_port,
                        value: KernelValue::from("tick"),
                        seq: CausalSeq::new(2, 2),
                    },
                ),
            ])
            .expect("later ticks execute");

        assert_eq!(
            executor.sink_value(program.result_sink),
            Some(&KernelValue::from(12.0))
        );

        executor
            .apply_messages(&[(
                actor,
                Msg::SourcePulse {
                    port: program.subtraction_press_port,
                    value: KernelValue::from("press"),
                    seq: CausalSeq::new(3, 0),
                },
            )])
            .expect("subtraction press executes");

        assert_eq!(
            executor.sink_value(program.result_sink),
            Some(&KernelValue::from(-16.0))
        );
    }

